INSERT OR REPLACE INTO artists (id, slug, honorific, name, city, region, bio, portrait_from, portrait_to, accepting_commissions, years_practicing, starting_at, custom_pricing, diocese_name, order_slug, vocation_statement, patron) VALUES ('art_maria_chrysostom', 'maria-chrysostom', NULL, 'Maria Chrysostom', 'Pittsburgh, Pennsylvania', 'United States', '["Maria trained at the Prosopon School and at the monastic workshops of Mount Athos. Her practice is rooted in the prayer rule of the iconographer: the work begins with fasting, continues with petition, and ends in obedience to the canon.","She has written for parishes, monasteries, and private chapels across North America. Her Marian commissions are particularly sought, and she keeps a small list of pilgrims for whom she writes Theotokos icons over the course of forty days."]', '#a8893f', '#42101a', 1, 14, 1800, 1, 'Diocese of Pittsburgh', NULL, 'I write icons in the Byzantine canon — egg tempera, gold leaf, gesso ground — as windows into the kingdom that is and is to come.', 'St. John Chrysostom');
INSERT OR REPLACE INTO artist_categories (artist_id, category_slug) VALUES ('art_maria_chrysostom', 'iconography');
