INSERT OR REPLACE INTO artist_tiers (id, artist_id, tier_id, name, description, starting_at, turnaround_weeks_min, turnaround_weeks_max, sort_order) VALUES ('tier_maria-chrysostom_standard', 'art_maria_chrysostom', 'standard', 'Parish Icon', 'Full canon icon for parish use. Up to 24×30 inches with gold halo and inscription.', 4200, 16, 24, 1);
INSERT OR REPLACE INTO artist_tiers (id, artist_id, tier_id, name, description, starting_at, turnaround_weeks_min, turnaround_weeks_max, sort_order) VALUES ('tier_maria-chrysostom_major', 'art_maria_chrysostom', 'major', 'Liturgical Cycle', 'Cycles of related icons — deesis, festal, hagiographic — for sanctuary or chapel.', 12000, 36, 60, 2);
