INSERT OR REPLACE INTO artists (id, slug, honorific, name, city, region, bio, portrait_from, portrait_to, accepting_commissions, years_practicing, starting_at, custom_pricing, diocese_name, order_slug, vocation_statement, patron) VALUES ('art_br_andrew_of_subiaco', 'br-andrew-of-subiaco', 'Br.', 'Andrew of Subiaco', 'Subiaco, Lazio', 'Italy', '["A Benedictine of the Subiaco Cassinese congregation, Br. Andrew has carved corpora, altar fronts, and devotional figures since taking solemn vows in 2003. He keeps the Liturgy of the Hours and works between Lauds and Vespers.","His pieces are spare, weighty, and unsentimental. He works primarily in travertine, walnut, and cherry, finishing wood with hand-rubbed beeswax and stone with a bush hammer."]', '#3a3024', '#1c160e', 1, 22, 3400, 1, 'Diocese of Tivoli', 'benedictine', 'Stone is patient. The figure is already there; my work is only to remove what is not the figure.', 'St. Benedict');
