INSERT OR REPLACE INTO artists (id, slug, honorific, name, city, region, bio, portrait_from, portrait_to, accepting_commissions, years_practicing, starting_at, custom_pricing, diocese_name, order_slug, vocation_statement, patron) VALUES ('art_giovanna_solis', 'giovanna-solis', NULL, 'Giovanna Solís', 'Ciudad de México', 'Mexico', '["Giovanna studied composition at the Conservatorio Nacional and choral conducting at the Pontifical Institute of Sacred Music in Rome. She conducts the Coro de la Asunción and writes for parishes across Latin America.","Her settings are modal, polyphonic, and singable — designed for parish choirs of modest size, with optional descant lines for feast days."]', '#535835', '#876b2c', 1, 17, 900, 1, 'Archdiocese of Mexico', NULL, 'I compose for choirs of breath and bone — Mass settings, motets, and household hymns that the people of God can carry in their voices.', 'St. Cecilia');
