INSERT OR REPLACE INTO artists (id, slug, honorific, name, city, region, bio, portrait_from, portrait_to, accepting_commissions, years_practicing, starting_at, custom_pricing, diocese_name, order_slug, vocation_statement, patron) VALUES ('art_tobias_wren', 'tobias-wren', NULL, 'Tobias Wren', 'Falmouth, Cornwall', 'United Kingdom', '["Tobias trained at the Florence Academy of Art and apprenticed under the late Giuliano Borghini in Bologna. He works from a converted chapel above the Helford estuary.","His Passion-cycle paintings have been commissioned for parishes in Cornwall, Connecticut, and South Australia. He paints by north light only."]', '#42101a', '#1c160e', 1, 19, 5400, 1, 'Diocese of Plymouth', NULL, 'I paint slowly, in oil on linen, with the dark grounds and warm glazes of the late Italian Baroque — for the Passion above all.', 'St. Luke');
