INSERT OR REPLACE INTO artists (id, slug, honorific, name, city, region, bio, portrait_from, portrait_to, accepting_commissions, years_practicing, starting_at, custom_pricing, diocese_name, order_slug, vocation_statement, patron) VALUES ('art_annunciata_park', 'annunciata-park', NULL, 'Annunciata Park', 'Seoul', 'South Korea', '["Annunciata trained at the Royal College of Art and at Atelier Loire in the Loire Valley. Her studio in Seongbuk-gu produces leaded windows and copper-foil work for parishes across Asia.","Her windows favour deep cobalts, hot golds, and the chartreuse the French call vert anglais — colours that read across a nave at noon and at Compline."]', '#1d3a6b', '#28477a', 1, 11, 6800, 1, 'Archdiocese of Seoul', NULL, 'Glass is the architecture of light. I cut and lead it so that the morning sun preaches the homily before the priest does.', 'Our Lady of the Annunciation');
