INSERT OR REPLACE INTO artists (id, slug, honorific, name, city, region, bio, portrait_from, portrait_to, accepting_commissions, years_practicing, starting_at, custom_pricing, diocese_name, order_slug, vocation_statement, patron) VALUES ('art_felix_donnegan', 'felix-donnegan', NULL, 'Felix Donnegan', 'Galway', 'Ireland', '["Felix read English at Trinity College Dublin and trained briefly with the Dominican preachers of St. Saviour''s. He writes sonnets, litanies, and prose-poems for private commissions, and a small annual cycle for the parish of St. Augustine.","Each commission is hand-set on a Vandercook proof press in Galway, on Hahnemühle paper, and signed."]', '#876b2c', '#535835', 1, 9, 380, 0, 'Diocese of Galway, Kilmacduagh & Kilfenora', NULL, 'I write occasional verse for the seasons of a Catholic life — births and weddings, requiems and feast days — in metre and rhyme, by hand.', 'St. Brigid');
