INSERT OR REPLACE INTO artists (id, slug, honorific, name, city, region, bio, portrait_from, portrait_to, accepting_commissions, years_practicing, starting_at, custom_pricing, diocese_name, order_slug, vocation_statement, patron) VALUES ('art_sr_clare_of_avila', 'sr-clare-of-avila', 'Sr.', 'Clare of Ávila', 'Abiquiú, New Mexico', 'United States', '["A Carmelite tertiary in the secular order, Sr. Clare paints from a small adobe studio in northern New Mexico. Her work is in the tradition of medieval marginalia: small, witty, devout, deeply seen.","She is sought for personal missals, illuminated initials for handbound books, and miniature portraits of patron saints."]', '#c9b072', '#876b2c', 1, 13, 540, 1, 'Archdiocese of Santa Fe', 'discalced-carmelite', 'I work small. Watercolour and ink, illuminated initials, miniatures the size of a hand — for breviaries, missals, and hidden devotion.', 'St. Clare of Assisi');
