INSERT OR REPLACE INTO artists (id, slug, honorific, name, city, region, bio, portrait_from, portrait_to, accepting_commissions, years_practicing, starting_at, custom_pricing, diocese_name, order_slug, vocation_statement, patron) VALUES ('art_henrik_aslaksen', 'henrik-aslaksen', NULL, 'Henrik Aslaksen', 'Bergen', 'Norway', '["Henrik works in 4×5 view-camera photography, with film developed and printed by hand in his Bergen darkroom. He has documented pilgrimage routes from Trondheim to Santiago de Compostela.","His commissioned work includes documentary cycles of parish life, family portraits in the Old Master tradition, and silver gelatin prints of liturgical celebrations."]', '#28477a', '#1c160e', 1, 16, 1600, 1, 'Diocese of Oslo', NULL, 'I photograph slowly, in large format and silver gelatin — pilgrimage, liturgy, and the long Northern light.', 'St. Sunniva');
