INSERT OR REPLACE INTO artists (id, slug, honorific, name, city, region, bio, portrait_from, portrait_to, accepting_commissions, years_practicing, starting_at, custom_pricing, diocese_name, order_slug, vocation_statement, patron) VALUES ('art_theo_marchand', 'theo-marchand', NULL, 'Théo Marchand', 'Lyon', 'France', '["Théo studied composition at the Conservatoire de Lyon and organ at the Schola Cantorum in Paris. He is organiste suppléant at the Primatiale Saint-Jean.","His commissioned hymns and Mass settings are published in small letterpress editions for parishes across the Francophone world."]', '#535835', '#1c160e', 1, 12, 700, 1, 'Archdiocese of Lyon', 'dominican', 'I write for the organ and the parish choir — chant-rooted, modal, made to fit the throat of an actual congregation.', 'St. Pothinus');
