INSERT OR REPLACE INTO artists (id, slug, honorific, name, city, region, bio, portrait_from, portrait_to, accepting_commissions, years_practicing, starting_at, custom_pricing, diocese_name, order_slug, vocation_statement, patron) VALUES ('art_imogen_fairbairn', 'imogen-fairbairn', NULL, 'Imogen Fairbairn', 'Edinburgh, Scotland', 'United Kingdom', '["Imogen read Theology at St. Andrews and trained at the Royal Conservatoire of Scotland. She writes liturgical drama in the tradition of the York and Wakefield cycles, in modern English with a strong sense of liturgy.","Her plays have been staged in parishes from Glasgow to Boston. She offers a pre-staging consultation and trains parish casts via video."]', '#42101a', '#3a3024', 1, 10, 1100, 0, 'Archdiocese of St Andrews & Edinburgh', NULL, 'I write mystery plays, scripted devotions, and Stations cycles — for parish halls, school chapels, and the open street.', 'St. Margaret of Scotland');
